#include <stdio.h>
#include <stdlib.h>

// Structure to represent a graph
typedef struct {
    int numNodes;
    int numEdges;
    int** edges;
} Graph;

// Function to create a new graph
Graph* createGraph(int numNodes, int numEdges) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->numNodes = numNodes;
    graph->numEdges = numEdges;
    graph->edges = (int**) malloc(numEdges * sizeof(int*));
    for (int i = 0; i < numEdges; i++) {
        graph->edges[i] = (int*) malloc(2 * sizeof(int));
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int edgeIndex, int node1, int node2) {
    graph->edges[edgeIndex][0] = node1;
    graph->edges[edgeIndex][1] = node2;
}

// Function to check if a valid partition exists
void checkPartition(Graph* graph) {
    int* setA = (int*) malloc(graph->numNodes * sizeof(int));
    int* setB = (int*) malloc(graph->numNodes * sizeof(int));
    for (int i = 0; i < graph->numNodes; i++) {
        setA[i] = 0;
        setB[i] = 0;
    }
    for (int i = 0; i < graph->numEdges; i++) {
        int node1 = graph->edges[i][0] - 1;
        int node2 = graph->edges[i][1] - 1;
        if (!setA[node1] && !setB[node1]) {
            setA[node1] = 1;
        }
        if (!setA[node2] && !setB[node2]) {
            setB[node2] = 1;
        }
    }
    int validPartition = 1;
    for (int i = 0; i < graph->numEdges; i++) {
        int node1 = graph->edges[i][0] - 1;
        int node2 = graph->edges[i][1] - 1;
        if (!setA[node1] && !setA[node2]) {
            validPartition = 0;
            break;
        }
    }
    if (validPartition) {
        printf("possible\n");
        for (int i = 0; i < graph->numNodes; i++) {
            if (setA[i]) {
                printf("1");
            } else {
                printf("0");
            }
        }
        printf("\n");
    } else {
        printf("impossible\n");
    }
    free(setA);
    free(setB);
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N, M;
        scanf("%d %d", &N, &M);
        Graph* graph = createGraph(N, M);
        for (int i = 0; i < M; i++) {
            int node1, node2;
            scanf("%d %d", &node1, &node2);
            addEdge(graph, i, node1, node2);
        }
        checkPartition(graph);
        for (int i = 0; i < M; i++) {
            free(graph->edges[i]);
        }
        free(graph->edges);
        free(graph);
    }
    return 0;
}

